const https = require('https');

function httpReq(url, options = {}) {
  return new Promise((resolve, reject) => {
    const m = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!m) { reject(new Error('Invalid URL: ' + url)); return; }
    const hostname = m[1];
    const path = m[2] || '/';
    const postData = options.body || '';
    const req = https.request({
      hostname: hostname,
      port: 443,
      path: path,
      method: options.method || 'GET',
      headers: { ...options.headers, ...(postData ? { 'Content-Length': Buffer.byteLength(postData) } : {}) }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const body = Buffer.concat(chunks).toString();
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, text: () => Promise.resolve(body), json: () => Promise.resolve(JSON.parse(body)), headers: res.headers });
      });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('Request timeout')); });
    if (postData) req.write(postData);
    req.end();
  });
}

// ============================================================
// Katalync - Shopify Sync Pull
// Full pipeline: auth → fetch vendor → paginate Shopify API →
// map products → upsert to Supabase → log results
// ============================================================

const input = $input.first().json;
const body = input.body || input;
const { token, vendor_id } = body;

// --- System token for scheduled sync ---
const SYSTEM_SYNC_SECRET = 'ks_sys_8f3a2b1c4d5e6f7a8b9c0d1e2f3a4b5c';
let isSystemSync = false;

// --- Constants ---
const SUPABASE_URL = 'https://prometeix-servidor-supabase.reyl9a.easypanel.host/rest/v1';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJzZXJ2aWNlX3JvbGUiLAogICAgImlzcyI6ICJzdXBhYmFzZS1kZW1vIiwKICAgICJpYXQiOiAxNjQxNzY5MjAwLAogICAgImV4cCI6IDE3OTk1MzU2MDAKfQ.DaYlNEoUrrEn2Ig7tqibS-PHK5vgusbcbo7X36XVt4Q';
const sbHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// --- Helper: Supabase request ---
async function sbFetch(path, options = {}) {
  const url = `${SUPABASE_URL}${path}`;
  const resp = await httpReq(url, {
    headers: { ...sbHeaders, ...(options.headers || {}) },
    method: options.method || 'GET',
    body: options.body ? JSON.stringify(options.body) : undefined
  });
  const text = await resp.text();
  if (!resp.ok) {
    throw new Error(`Supabase ${options.method || 'GET'} ${path} failed (${resp.status}): ${text}`);
  }
  return text ? JSON.parse(text) : null;
}

// --- Helper: safe string ---
function safeStr(val, fallback = '') {
  if (val === null || val === undefined) return fallback;
  return String(val).trim() || fallback;
}

// --- Helper: safe float ---
function safeFloat(val, fallback = 0) {
  const n = parseFloat(val);
  return isNaN(n) ? fallback : n;
}

// --- Helper: safe int ---
function safeInt(val, fallback = 0) {
  const n = parseInt(val, 10);
  return isNaN(n) ? fallback : n;
}

try {
  // ========== STEP 1: Verify token ==========
  if (!token || typeof token !== 'string') {
    return [{ json: { success: false, error: 'Missing or invalid token' } }];
  }
  if (!vendor_id) {
    return [{ json: { success: false, error: 'Missing vendor_id' } }];
  }

  let user_id = null;

  if (token === SYSTEM_SYNC_SECRET) {
    isSystemSync = true;
  } else {
    // Auth verification — call auth-verify endpoint
    const authResp = await httpReq('https://api.katalync.com/webhook/auth-verify', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ token })
    });
    const authData = await authResp.json();
    if (!authData.success) {
      return [{ json: { success: false, error: authData.error || 'Token invalid or expired' } }];
    }
    const userEmail = authData.email;

    // Upsert user into Supabase (auto-provision from n8n session data)
    const upsertData = await sbFetch('/users?on_conflict=email', {
      method: 'POST',
      headers: { 'Prefer': 'resolution=merge-duplicates,return=representation' },
      body: [{
        email: authData.email,
        name: authData.name || authData.email,
        password_hash: 'oauth-managed',
        role: authData.role || 'user',
        company: authData.company || null,
        lang: authData.lang || 'es',
        onboarded: authData.onboarded || false,
        subscription_status: authData.subscription_status || 'active',
        last_login_at: new Date().toISOString()
      }]
    });
    user_id = upsertData && upsertData.length > 0 ? upsertData[0].id : null;
    if (!user_id) {
      return [{ json: { success: false, error: 'Failed to provision user' } }];
    }
  }

  // ========== STEP 2: Fetch vendor ==========
  const vendorQuery = isSystemSync
    ? `/vendors?id=eq.${vendor_id}&select=*`
    : `/vendors?id=eq.${vendor_id}&user_id=eq.${user_id}&select=*`;
  const vendors = await sbFetch(vendorQuery);
  if (!vendors || vendors.length === 0) {
    return [{ json: { success: false, error: 'Vendor not found or access denied' } }];
  }
  const vendor = vendors[0];

  // ========== STEP 3: Validate source ==========
  if (vendor.source !== 'shopify') {
    return [{ json: { success: false, error: `Vendor source is '${vendor.source}', expected 'shopify'` } }];
  }

  if (!vendor.source_url || !vendor.source_api_key) {
    return [{ json: { success: false, error: 'Vendor missing source_url or source_api_key' } }];
  }

  // Normalize source_url: remove trailing slash
  const shopifyUrl = vendor.source_url.replace(/\/+$/, '');
  const accessToken = vendor.source_api_key;

  // ========== STEP 4: Create sync_log ==========
  const startedAt = new Date().toISOString();
  const syncLogs = await sbFetch('/sync_logs', {
    method: 'POST',
    body: {
      vendor_id: vendor.id,
      direction: 'pull',
      total_products: 0,
      created_count: 0,
      updated_count: 0,
      error_count: 0,
      status: 'running',
      started_at: startedAt
    }
  });
  const syncLog = syncLogs[0];
  const sync_log_id = syncLog.id;

  // ========== STEP 5-7: Fetch ALL Shopify products (with pagination) ==========
  let allProducts = [];
  let nextUrl = `${shopifyUrl}/admin/api/2024-01/products.json?limit=250&status=active`;
  let pageCount = 0;
  const MAX_PAGES = 100; // Safety limit: 100 pages * 250 = 25,000 products max

  while (nextUrl && pageCount < MAX_PAGES) {
    pageCount++;
    let resp;
    try {
      resp = await httpReq(nextUrl, {
        method: 'GET',
        headers: {
          'X-Shopify-Access-Token': accessToken,
          'Content-Type': 'application/json'
        }
      });
    } catch (fetchErr) {
      throw new Error(`Shopify API connection failed (page ${pageCount}): ${fetchErr.message}`);
    }

    if (!resp.ok) {
      const errText = await resp.text();
      throw new Error(`Shopify API error ${resp.status} (page ${pageCount}): ${errText.substring(0, 500)}`);
    }

    const data = await resp.json();
    if (data.products && Array.isArray(data.products)) {
      allProducts = allProducts.concat(data.products);
    }

    // Parse Link header for pagination
    nextUrl = null;
    const linkHeader = resp.headers['link'];
    if (linkHeader) {
      const matches = linkHeader.match(/<([^>]+)>;\s*rel="next"/);
      if (matches && matches[1]) {
        nextUrl = matches[1];
      }
    }

    // Rate limiting: Shopify allows 2 req/sec at basic tier
    if (nextUrl) {
      await new Promise(resolve => setTimeout(resolve, 600));
    }
  }

  // ========== STEP 7 (continued): Map Shopify products to Katalync format ==========
  const mappedProducts = [];
  const syncErrors = [];

  for (const product of allProducts) {
    try {
      const variants = product.variants || [];
      if (variants.length === 0) {
        // Product with no variants — skip but log
        syncErrors.push({
          sync_log_id,
          sku: safeStr(product.id),
          field: 'variants',
          error_type: 'missing_data',
          message: `Product ${product.id} (${safeStr(product.title)}) has no variants`
        });
        continue;
      }

      for (const variant of variants) {
        try {
          // Build SKU
          let sku = safeStr(variant.sku);
          if (!sku) {
            sku = `${product.id}-${variant.id}`;
          }

          // Build name
          let name = safeStr(product.title, 'Untitled');
          const variantTitle = safeStr(variant.title);
          if (variantTitle && variantTitle !== 'Default Title') {
            name = `${name} - ${variantTitle}`;
          }

          // Find image
          let imageUrl = '';
          if (variant.image_id && product.images && product.images.length > 0) {
            const variantImage = product.images.find(img => img.id === variant.image_id);
            imageUrl = variantImage ? variantImage.src : '';
          }
          if (!imageUrl && product.images && product.images.length > 0) {
            imageUrl = product.images[0].src || '';
          }
          // Remove query params from Shopify CDN URLs for cleaner storage
          if (imageUrl && imageUrl.includes('?')) {
            imageUrl = imageUrl.split('?')[0];
          }

          const mapped = {
            vendor_id: vendor.id,
            sku: sku,
            ean: safeStr(variant.barcode),
            name: name.substring(0, 500), // Reasonable limit
            brand: safeStr(product.vendor),
            category: safeStr(product.product_type),
            price: safeFloat(variant.price),
            stock: safeInt(variant.inventory_quantity, 0),
            image_url: imageUrl,
            raw_data: {
              shopify_product_id: product.id,
              shopify_variant_id: variant.id,
              shopify_handle: product.handle,
              shopify_status: product.status,
              shopify_tags: product.tags,
              variant_title: variant.title,
              variant_option1: variant.option1,
              variant_option2: variant.option2,
              variant_option3: variant.option3,
              variant_weight: variant.weight,
              variant_weight_unit: variant.weight_unit,
              variant_inventory_item_id: variant.inventory_item_id,
              variant_fulfillment_service: variant.fulfillment_service,
              compare_at_price: variant.compare_at_price,
              requires_shipping: variant.requires_shipping,
              taxable: variant.taxable
            },
            sync_status: 'synced',
            last_synced_at: new Date().toISOString()
          };

          mappedProducts.push(mapped);
        } catch (variantErr) {
          syncErrors.push({
            sync_log_id,
            sku: safeStr(variant.sku || `${product.id}-${variant.id}`),
            field: 'variant_mapping',
            error_type: 'mapping_error',
            message: `Error mapping variant ${variant.id}: ${variantErr.message}`
          });
        }
      }
    } catch (productErr) {
      syncErrors.push({
        sync_log_id,
        sku: safeStr(product.id),
        field: 'product_mapping',
        error_type: 'mapping_error',
        message: `Error mapping product ${product.id}: ${productErr.message}`
      });
    }
  }

  // ========== STEP 8: Delta sync + Upsert products ==========
  let createdCount = 0;
  let updatedCount = 0;
  let unchangedCount = 0;
  let errorCount = syncErrors.length;
  const BATCH_SIZE = 50;

  // Fetch existing products with comparison fields
  const existingProducts = await sbFetch(
    `/vendor_products?vendor_id=eq.${vendor.id}&select=sku,name,brand,category,price,stock,image_url,ean&limit=100000`
  );
  const existingMap = {};
  (existingProducts || []).forEach(p => { existingMap[p.sku] = p; });
  const existingSkus = new Set(Object.keys(existingMap));

  // Compare each product and set sync_status
  for (const mapped of mappedProducts) {
    const existing = existingMap[mapped.sku];
    if (!existing) {
      mapped.sync_status = 'new';
    } else {
      const changed = (
        mapped.name !== (existing.name || '') ||
        mapped.brand !== (existing.brand || '') ||
        mapped.category !== (existing.category || '') ||
        Math.round(mapped.price * 100) !== Math.round((existing.price || 0) * 100) ||
        mapped.stock !== (existing.stock || 0) ||
        mapped.image_url !== (existing.image_url || '') ||
        mapped.ean !== (existing.ean || '')
      );
      if (changed) {
        mapped.sync_status = 'changed';
        mapped.sprinter_product = null;
        mapped.sprinter_offer = null;
      } else {
        mapped.sync_status = 'unchanged';
        unchangedCount++;
      }
    }
  }

  // Only upsert new or changed products
  const productsToUpsert = mappedProducts.filter(p => p.sync_status !== 'unchanged');

  // Upsert in batches
  for (let i = 0; i < productsToUpsert.length; i += BATCH_SIZE) {
    const batch = productsToUpsert.slice(i, i + BATCH_SIZE);

    try {
      await sbFetch('/vendor_products', {
        method: 'POST',
        headers: {
          'Prefer': 'resolution=merge-duplicates,return=representation'
        },
        body: batch
      });

      // Count created vs updated
      for (const item of batch) {
        if (existingSkus.has(item.sku)) {
          updatedCount++;
        } else {
          createdCount++;
        }
      }
    } catch (upsertErr) {
      // If batch fails, try individual inserts
      for (const item of batch) {
        try {
          await sbFetch('/vendor_products', {
            method: 'POST',
            headers: {
              'Prefer': 'resolution=merge-duplicates,return=representation'
            },
            body: [item]
          });
          if (existingSkus.has(item.sku)) {
            updatedCount++;
          } else {
            createdCount++;
          }
        } catch (itemErr) {
          errorCount++;
          syncErrors.push({
            sync_log_id,
            sku: item.sku,
            field: 'upsert',
            error_type: 'database_error',
            message: `Upsert failed: ${itemErr.message}`.substring(0, 500)
          });
        }
      }
    }
  }

  // ========== STEP 9: Update sync_log ==========
  const completedAt = new Date().toISOString();
  await sbFetch(`/sync_logs?id=eq.${sync_log_id}`, {
    method: 'PATCH',
    body: {
      status: errorCount > 0 ? 'completed_with_errors' : 'completed',
      total_products: mappedProducts.length,
      created_count: createdCount,
      updated_count: updatedCount,
      error_count: errorCount,
      error_details: syncErrors.length > 0 ? syncErrors.slice(0, 100) : null,
      completed_at: completedAt
    }
  });

  // ========== STEP 10: Update vendor ==========
  const syncInterval = vendor.sync_interval_hours || 24;
  const nextSyncAt = new Date(Date.now() + syncInterval * 60 * 60 * 1000).toISOString();

  await sbFetch(`/vendors?id=eq.${vendor.id}`, {
    method: 'PATCH',
    body: {
      product_count: createdCount + updatedCount,
      sync_status: errorCount > 0 ? 'completed_with_errors' : 'synced',
      last_sync_at: completedAt,
      next_sync_at: nextSyncAt,
      last_sync_products_synced: createdCount + updatedCount,
      last_sync_errors: errorCount
    }
  });

  // ========== STEP 11: Insert sync_errors ==========
  if (syncErrors.length > 0) {
    // Insert in batches of 50
    for (let i = 0; i < syncErrors.length; i += BATCH_SIZE) {
      const errorBatch = syncErrors.slice(i, i + BATCH_SIZE);
      try {
        await sbFetch('/sync_errors', {
          method: 'POST',
          body: errorBatch
        });
      } catch (e) {
        // Don't fail the whole sync just because error logging failed
        console.log('Warning: Failed to log sync errors batch:', e.message);
      }
    }
  }


  // ========== STEP 11.5: Trigger auto-convert (fire-and-forget) ==========
  if (productsToUpsert.length > 0) {
    httpReq('https://api.katalync.com/webhook/auto-convert', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        token: isSystemSync ? SYSTEM_SYNC_SECRET : token,
        vendor_id: vendor.id,
        marketplaces: (vendor.config && vendor.config.marketplaces) || ['sprinter_es']
      }),
      timeout: 5000
    }).catch(() => {});
  }

  // ========== STEP 12: Return result ==========
  return [{
    json: {
      success: true,
      vendor_id: vendor.id,
      vendor_name: vendor.name,
      source: 'shopify',
      total: mappedProducts.length,
      created: createdCount,
      updated: updatedCount,
      unchanged: unchangedCount,
      upserted: productsToUpsert.length,
      errors: errorCount,
      pages_fetched: pageCount,
      shopify_products: allProducts.length,
      sync_log_id: sync_log_id,
      scheduled: isSystemSync,
      duration_ms: Date.now() - new Date(startedAt).getTime()
    }
  }];

} catch (fatalError) {
  // Fatal error handler — update sync_log if possible
  try {
    if (typeof sync_log_id !== 'undefined') {
      await sbFetch(`/sync_logs?id=eq.${sync_log_id}`, {
        method: 'PATCH',
        body: {
          status: 'failed',
          error_details: [{ error: fatalError.message }],
          completed_at: new Date().toISOString()
        }
      });
    }
    if (typeof vendor !== 'undefined') {
      await sbFetch(`/vendors?id=eq.${vendor.id}`, {
        method: 'PATCH',
        body: {
          sync_status: 'error'
        }
      });
    }
  } catch (e) {
    // Best effort
  }

  return [{
    json: {
      success: false,
      error: fatalError.message,
      vendor_id: body.vendor_id || null
    }
  }];
}
